import play.api._
import play.api.mvc._
import java.nio.file.{Files, Path}
import scala.collection.JavaConverters._
 
class FileDownloadController extends Controller {  
     def download(filename : String) = Action.async { implicit request =>      
         val filePath: Path =  s"uploads/$filename";   
          Files.exists(filePath); // Ensure the path exists       
           scala.io.Source.fromFile(new java.nio.file.Files().toFile).getLines()   .foreach((line) => {  println (line)} );     if (!filename.isEmpty())          return Ok("Downloaded file " + filename); else         throw new NotFoundException();}}